#include <stdio.h>
#include <stdlib.h>

int cmp_desc(const void *a, const void *b) {
    int x = *(int *)b - *(int *)a; // descending
    return x;
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N, K; scanf("%d %d", &N, &K);
        long long sumPos = 0;
        int *neg = (int *)malloc(N * sizeof(int));
        int negCnt = 0;
        for (int i = 0; i < N; ++i) {
            int x; scanf("%d", &x);
            if (x >= 0) sumPos += x;
            else { neg[negCnt++] = -x; } // store absolute value
        }
        qsort(neg, negCnt, sizeof(int), cmp_desc);
        long long add = 0;
        int take = K < negCnt ? K : negCnt;
        for (int i = 0; i < take; ++i) add += neg[i];
        printf("%lld\n", sumPos + add);
        free(neg);
    }
    return 0;
}

