#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it)); K = int(next(it))
        sum_pos = 0
        neg = []
        for _ in range(N):
            x = int(next(it))
            if x >= 0:
                sum_pos += x
            else:
                neg.append(-x)  # absolute value
        neg.sort(reverse=True)
        add = sum(neg[:min(K, len(neg))])
        out_lines.append(str(sum_pos + add))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

